// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#define MAX_N 1000
#define MAX_M 2

// Structure to represent an edge in the graph
typedef struct {
    int u, v;
    double weight;
} Edge;

// Comparison function for sorting edges
int compareEdges(const void *a, const void *b) {
    Edge *e1 = (Edge *)a;
    Edge *e2 = (Edge *)b;
    return (e1->weight > e2->weight) ? 1 : -1;
}

// Function to find the minimum spanning tree using Kruskal's algorithm
double findMST(int N, int M, Edge *edges, int *parent) {
    double totalWeight = 0.0;
    int numEdges = 0;

    // Sort the edges in non-decreasing order of their weights
    qsort(edges, M, sizeof(Edge), compareEdges);

    // Initialize the parent array for the disjoint set data structure
    for (int i = 0; i < N; i++) {
        parent[i] = i;
    }

    // Iterate over the sorted edges and add them to the minimum spanning tree if they do not form a cycle
    for (int i = 0; i < M; i++) {
        int u = edges[i].u;
        int v = edges[i].v;

        // Find the roots of the sets containing u and v
        int rootU = find(parent, u);
        int rootV = find(parent, v);

        // If u and v are not in the same set, add the edge to the minimum spanning tree and merge the sets
        if (rootU != rootV) {
            totalWeight += edges[i].weight;
            numEdges++;
            parent[rootU] = rootV;
        }
    }

    return totalWeight;
}

// Function to find the root of a set in the disjoint set data structure
int find(int *parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}

int main() {
    int T;
    scanf("%d", &T);

    for (int t = 0; t < T; t++) {
        int N, M;
        double C;
        scanf("%d %lf %d", &N, &C, &M);

        Edge edges[MAX_M];
        int parent[MAX_N];

        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            edges[i].u = u - 1;
            edges[i].v = v - 1;
            edges[i].weight = 0.0;
        }

        double totalWeight = findMST(N, M, edges, parent);

        printf("%.9f\n", totalWeight + (N - 1 - M) * C);
    }

    return 0;
}

