public class Main {
    // Structure to represent an edge in the graph
    static class Edge implements Comparable<Edge> {
        int u, v;
        double weight;

        public Edge(int u, int v, double weight) {
            this.u = u;
            this.v = v;
            this.weight = weight;
        }

        @Override
        public int compareTo(Edge o) {
            return Double.compare(weight, o.weight);
        }
    }

    // Function to find the minimum spanning tree using Kruskal's algorithm
    public static double findMST(int N, int M, Edge[] edges, int[] parent) {
        double totalWeight = 0.0;
        int numEdges = 0;

        // Sort the edges in non-decreasing order of their weights
        Arrays.sort(edges);

        // Initialize the parent array for the disjoint set data structure
        for (int i = 0; i < N; i++) {
            parent[i] = i;
        }

        // Iterate over the sorted edges and add them to the minimum spanning tree if they do not form a cycle
        for (int i = 0; i < M; i++) {
            int u = edges[i].u;
            int v = edges[i].v;

            // Find the roots of the sets containing u and v
            int rootU = find(parent, u);
            int rootV = find(parent, v);

            // If u and v are not in the same set, add the edge to the minimum spanning tree and merge the sets
            if (rootU != rootV) {
                totalWeight += edges[i].weight;
                numEdges++;
                parent[rootU] = rootV;
            }
        }

        return totalWeight;
    }

    // Function to find the root of a set in the disjoint set data structure
    public static int find(int[] parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();

        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            double C = scanner.nextDouble();
            int M = scanner.nextInt();

            Edge[] edges = new Edge[M];
            int[] parent = new int[N];

            for (int i = 0; i < M; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                edges[i] = new Edge(u - 1, v - 1, 0.0);
            }

            double totalWeight = findMST(N, M, edges, parent);

            System.out.printf("%.9f\n", totalWeight + (N - 1 - M) * C);
        }

        scanner.close();
    }
}

